SELECT 
FROM sys_map


        AND del_flag = '0'


        AND map_id = #{mapId}


        AND robot_id = #{robotId}


        AND tenant_id = #{tenantId}


        AND map_name LIKE CONCAT('%', #{mapName}, '%')


        AND status = #{status}


